export default function BlogDetailPage({ params }: { params: { id: string } }) {
  const blog = blogs.find(b => b.id === params.id);
  if (!blog) return notFound();

  return (
    <div className="bg-black text-white min-h-screen">
      {/* Hero Section */}
      <div className="w-full bg-cover bg-center bg-black" style={{ backgroundImage: 'url(/media/Inner_bg.23beb686.jpg)' }}>
        <div className="w-full h-full flex items-center justify-center py-32 relative bg-cover bg-center bg-no-repeat">
          <div className="flex flex-col justify-center items-center gap-8 font-semibold text-white">
            <span className="text-center text-5xl xl:text-7xl">{blog.title}</span>
            {/* Breadcrumbs */}
            <nav aria-label="breadcrumb">
              <ul className="flex items-center space-x-2 text-lg font-semibold text-white py-1.5 px-2">
                <li><Link className="hover:underline" href="/">Home</Link></li>
                <li className="flex items-center"><span className="mx-2">*</span><Link className="hover:underline" href="/blogs">Blogs</Link></li>
                <li className="flex items-center"><span className="mx-2">*</span><span className="text-[#86c232]">{blog.id}</span></li>
              </ul>
            </nav>
          </div>
        </div>
      </div>
      {/* Blog Content */}
      <div className="container mx-auto py-20">
        {blog.content.map((block, idx) => {
          if (block.type === 'heading') {
            return <h3 key={idx} className="font-bold text-3xl mt-10 mb-4">{block.text}</h3>;
          }
          if (block.type === 'paragraph') {
            return <p key={idx} className="mt-5 text-lg text-gray-200">{block.text}</p>;
          }
          return null;
        })}
      </div>
    </div>
  );
} 